"use client";

import React from "react";
import Link from "next/link";
import Image from "next/image";

const services = [
  {
    title: "Air Conditioner",
    desc: "Specializing in buying used AC units from commercial buildings, we ensure hassle-free pickup and responsible recycling.",
    img: "/images/Air con-compressed.jpg",
    link: "/AC.html", // TODO: Update link when page exists
  },
  {
    title: "Electrical Scrap",
    desc: "Purchase old office electric scrap such as wires cables and used electronic device from caproate office",
    img: "/images/electrical scrap-compressed.jpg",
    link: "/electrical.html",
  },
  {
    title: "Metal Scrap",
    desc: "We specialize in purchasing and recycling various types of metal scrap, including aluminum, copper, and steel in Kolkata",
    img: "/images/coppper crop.jpg",
    link: "/metal.html",
  },
  {
    title: "Battery Recycling",
    desc: "We specialize in purchasing workstations and office furniture from corporate, institution, and banking sector",
    img: "/images/bettery recycling.jpeg",
    link: "/battery.html",
  },
  {
    title: "Corporate Scrap",
    desc: "Our Kolkata-based scrap company buy corporate office scrap, ensuring eco-friendly disposal and top prices.",
    img: "/images/office furniture scrap.jpeg",
    link: "/corporate.html",
  },
  {
    title: "Old DG Generator",
    desc: "We buy old office furniture like outdated desk, Office Scrap, cabinets, office chair to minimize office waste effectively",
    img: "/images/dg set crop.jpg",
    link: "/old-DG-Ganerator.html",
  },
  {
    title: "IT Asset Disposition",
    desc: "IT Asset Disposition services prioritize security for IT disposal, ensuring the best price and offering the best service in Kolkata",
    img: "/images/IT Asset Disposition Buyer.jpeg",
    link: "/assetdisposiaton.html",
  },
  {
    title: "E-waste Recycling",
    desc: "Buy corporate Office E-waste item such as computers and Laptop for recycling ensuring data security and environmental protection",
    img: "/images/e-waste-recycling-kolkata.jpeg",
    link: "/kolkata e-waste.html",
  },
];

const ServiceGrid = () => {
  return (
    <section id="team" className="team_wrapper wrapper bg-[#f9f9f9]">
      <div className="container mx-auto px-4">
        <div className="row mb-12 text-center">
          <div className="col-sm-12">
            <h3 className="text-text-black text-4xl mb-5 font-semibold font-secondary">
              Procurement Sources and services
            </h3>
          </div>
        </div>
        <div className="flex flex-wrap -mx-4">
          {services.map((service, index) => (
            <div key={index} className="w-full sm:w-1/2 md:w-1/4 px-4 mb-8">
              <Link href={service.link} className="block group bg-white rounded-[10px] shadow-[0.5084rem_1.1419rem_2.5rem_0_rgb(0,0,0,0.08)] p-[3.75rem_3.125rem_4.6875rem] transition-all duration-400 hover:-translate-y-[0.625rem] h-full text-center no-underline border-0">
                <div className="team-img mb-4 flex justify-center">
                  <div className="relative w-full aspect-square max-w-[200px] overflow-hidden rounded-lg">
                     <Image
                      src={service.img}
                      alt={service.title}
                      fill
                      className="object-cover"
                    />
                  </div>
                </div>
                <div className="team-info pt-4 text-center">
                  <h2 className="text-2xl font-semibold mb-2 text-text-black font-secondary">{service.title}</h2>
                  <p className="text-justify text-text-gray">{service.desc}</p>
                </div>
              </Link>
            </div>
          ))}
        </div>
        
        <div className="text-center mt-12 relative flex items-center justify-center">
            {/* Kaishu line animation not fully replicated as it's purely decorative, using simple line instead */}
            <div className="h-px bg-gray-300 w-full absolute top-1/2 -z-10"></div>
            <button className="bg-white border text-secondary border-secondary px-6 py-2 rounded shadow hover:bg-secondary hover:text-white transition-colors z-10">
                View More Services
            </button>
        </div>
      </div>
    </section>
  );
};

export default ServiceGrid;
