"use client";

import React from "react";
import { FaUser, FaBalanceScale, FaFileInvoice, FaHandshake } from "react-icons/fa";

const steps = [
  {
    icon: FaUser,
    step: 1,
    title: "Client Meeting",
    desc: "First step of our scrap buying process is to meet clients and discuss the overall requirements",
  },
  {
    icon: FaBalanceScale,
    step: 2,
    title: "Evaluation of Scrap",
    desc: "Second step is to evaluate scrap price as per standards that will suit both parties’ best",
  },
  {
    icon: FaFileInvoice,
    step: 3,
    title: "Quotation Subimt",
    desc: "In the third step, we send the best quotation after real-time/spot evaluation of scrap price",
  },
  {
    icon: FaHandshake,
    step: 4,
    title: "Execution",
    desc: "We execute the scrap moving process in 48 hours depending on the work volume",
  },
];

const ScrapBuyingProcess = () => {
  return (
    <section id="services" className="services_wrapper wrapper bg-[#fdfd0f]">
      <div className="container mx-auto px-4">
        <div className="text-center mb-12">
          <h3 className="text-[#127749] text-4xl font-semibold font-secondary mb-4">Our Scrap Buying process</h3>
          <p className="text-justify text-text-gray text-base max-w-3xl mx-auto">
            We've distilled our Scrap Buying process into 4 Steps – the same
            steps we have been using for more than 30 years to deliver fast
            and hassle-free service!
          </p>
        </div>
        <div className="flex flex-wrap -mx-4">
          {steps.map((item, index) => (
            <div key={index} className="w-full sm:w-1/2 md:w-1/4 px-4 mb-8">
              <div className="card service-item bg-white p-[3.75rem_3.125rem_4.6875rem] rounded-[10px] shadow-lg text-center h-full transition-all duration-400 hover:-translate-y-2.5">
                <div className="icon-box text-[3.125rem] text-secondary mb-6 flex justify-center items-center">
                  <item.icon className="mr-2" /> {item.step}
                </div>
                <div>
                  <h4 className="text-2xl font-semibold mb-4 text-black font-secondary">{item.title}</h4>
                  <p className="text-justify text-text-gray">{item.desc}</p>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default ScrapBuyingProcess;
