"use client";

import React from "react";
import Image from "next/image";

const Hero = () => {
  return (
    <section id="home" className="home relative">
      <div 
        className="banner_wrapper wrapper relative bg-cover bg-center bg-no-repeat min-h-[70vh] flex items-center"
        style={{ backgroundImage: 'url("/images/home page.jpg")' }}
      >
        <div className="container mx-auto px-4">
          <motion.div 
            initial={{ opacity: 0, y: 30 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.8, ease: "easeOut" }}
            className="flex flex-col md:flex-row items-center"
          >
            {/* Left Content */}
            <div className="w-full md:w-1/2 order-2 md:order-1 text-center md:text-left mt-8 md:mt-0">
              <h1 style={{ color: "wheat" }} className="font-secondary font-semibold text-4xl md:text-6xl mb-5">
                Office Scrap Buyers in Kolkata
              </h1>
            </div>

            {/* Right Form */}
            <div className="w-full md:w-1/2 order-1 md:order-2 mb-10 md:mb-0 flex justify-center md:justify-end">
              <div className="bg-white/90 p-5 rounded-lg shadow-lg max-w-[350px] w-full">
                <h4 className="text-2xl font-semibold mb-5 text-gray-800 font-secondary">Get in Touch</h4>
                <form id="contactForm" onSubmit={(e) => { e.preventDefault(); alert("Message sent! (Frontend only mode)"); }} className="mb-0">
                  <div className="mb-5">
                    <input
                      type="text"
                      className="w-full p-2.5 text-base border border-gray-300 rounded focus:outline-none focus:ring-2 focus:ring-secondary"
                      name="name"
                      placeholder="Your Name"
                      required
                    />
                  </div>
                  <div className="mb-5">
                    <input
                      type="number"
                      className="w-full p-2.5 text-base border border-gray-300 rounded focus:outline-none focus:ring-2 focus:ring-secondary"
                      name="number"
                      placeholder="Your Mobile"
                      required
                    />
                  </div>
                  <div className="mb-5">
                    <input
                      type="email"
                      className="w-full p-2.5 text-base border border-gray-300 rounded focus:outline-none focus:ring-2 focus:ring-secondary"
                      name="email"
                      placeholder="Your Email"
                      required
                    />
                  </div>
                  <button type="submit" className="main-btn mt-3 w-full bg-secondary border-secondary hover:bg-white hover:text-black">
                    Sale now
                  </button>
                </form>
              </div>
            </div>
          </motion.div>
        </div>
      </div>
    </section>
  );
};

export default Hero;
